    const tempId = Date.now().toString();
    const newSpace = { _id: tempId, name: newSpaceName, iconName: 'Folder', color: '#94a3b8', customTabs: [] };
    setSpaces([...spaces, newSpace]); setActiveSpace(newSpace); setActiveCustomTab(null); setActiveCategoryTab('ראשי'); setAddSpaceModalOpen(false); setNewSpaceName('');
