  const handleSaveSpaceSettings = async (e) => {
    e.preventDefault();
    const updatedSpaces = spaces.map(s => s._id === editingSpaceId ? { ...s, name: editSpaceData.name, iconName: editSpaceData.iconName, color: editSpaceData.color } : s);
    setSpaces(updatedSpaces); if (activeSpace._id === editingSpaceId) setActiveSpace(updatedSpaces.find(s => s._id === editingSpaceId)); setSettingsModalOpen(false);
    if (editingSpaceId !== 'default') { fetch(`/api/spaces/${editingSpaceId}`, { method: 'PUT', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify({ name: editSpaceData.name, iconName: editSpaceData.iconName, color: editSpaceData.color }) }); }
  };

  const openRenameSpace = () => { if (!spaceContextMenu.space) return; setNewSpaceName(spaceContextMenu.space.name); setRenameSpaceModalOpen(true); closeContextMenus(); };

